  setArtistName(name) { if (!name || typeof name !== "string") throw new Error("Artist name must be a non-empty string."); this.artistName = name; return this; }
  setReleaseYear(year) { if (year && typeof year !== "string" && typeof year !== "number") throw new Error("Release year must be a string or number if provided."); this.releaseYear = year.toString(); return this; }
  setTrackCount(count) { if (count && typeof count !== "number") throw new Error("Track count must be a number if provided."); if (count <= 0) throw new Error("Track count must be positive if provided."); this.trackCount = count; return this; }
