  // --- Setters for Visual Customization ---
  setBackgroundColor(color) { if (!color || !isValidHexColor(color)) throw new Error("Invalid background color. Use hex format."); this.backgroundColor = color; return this; }
  setImagePlaceholderColor(color) { if (!color || !isValidHexColor(color)) throw new Error("Invalid image placeholder color. Use hex format."); this.imagePlaceholderColor = color; return this; }
  setAlbumNameColor(color) { if (!color || !isValidHexColor(color)) throw new Error("Invalid album name color. Use hex format."); this.albumNameColor = color; return this; }
  setArtistNameColor(color) { if (!color || !isValidHexColor(color)) throw new Error("Invalid artist name color. Use hex format."); this.artistNameColor = color; return this; }
  setDetailsColor(color) { if (!color || !isValidHexColor(color)) throw new Error("Invalid details color. Use hex format."); this.detailsColor = color; return this; }
  setCardBorderColor(color) { if (color && !isValidHexColor(color)) throw new Error("Invalid card border color. Use hex format."); this.cardBorderColor = color; return this; }

