    const albumText = this.albumName.length > 25 ? this.albumName.slice(0, 22) + "..." : this.albumName;
    ctx.fillText(albumText, textStartX, textStartY);

    // Artist Name (Medium, smaller)
    ctx.fillStyle = this.artistNameColor;
    const artistFont = `16px ${registeredFontName}-Medium`; // Use registered name
    ctx.font = artistFont;
    const artistText = this.artistName.length > 30 ? this.artistName.slice(0, 27) + "..." : this.artistName;
